function sr_json($s,$m='',$x=array()){header('Content-Type: application/json; charset=utf-8');$p=array('status'=>$s);if($m!=='')$p[$s==='good'?'message':'error_message']=$m;foreach($x as $k=>$v)$p[$k]=$v;echo json_encode($p);exit;}
function sr_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function sr_p($k,$d=''){return isset($_POST[$k])?$_POST[$k]:$d;} function sr_g($k,$d=''){return isset($_GET[$k])?$_GET[$k]:$d;} function sr_c($v){return strtoupper(trim((string)$v));} function sr_user(){return isset($_SESSION['username'])&&$_SESSION['username']!==''?$_SESSION['username']:'system';}
function sr_select2($rows,$id,$cb){$out=array();foreach($rows as $r)$out[]=array('id'=>$r->$id,'text'=>$cb($r));header('Content-Type: application/json; charset=utf-8');echo json_encode(array('results'=>$out));exit;}
function sr_next_no($year){global $db;$year=(int)$year>0?(int)$year:(int)date('Y');$r=$db->fetch("SELECT selection_no FROM erp_selection_result WHERE selection_no LIKE ? ORDER BY selection_no DESC LIMIT 1",array('SEL-'.$year.'-%'));$n=1;if($r&&preg_match('/-(\d+)$/',$r->selection_no,$m))$n=(int)$m[1]+1;return 'SEL-'.$year.'-'.str_pad($n,3,'0',STR_PAD_LEFT);}
function sr_row($id){global $db;return $db->fetch("SELECT s.*,a.applicant_no,a.applicant_name,a.applicant_status,a.screening_score app_screening,a.interview_score app_interview,a.final_score app_final,v.vacancy_no,v.vacancy_title,v.position_id vacancy_position_id,v.job_title_id vacancy_job_title_id,v.pay_grade vacancy_grade,v.salary_min,v.salary_max,v.currency vacancy_currency,v.target_join_date,i.interview_no,pos.position_code,pos.position_name,jt.job_title_code,jt.job_title_name,app.employee_no approved_no,app.full_name approved_name FROM erp_selection_result s LEFT JOIN erp_applicant_data a ON a.id=s.applicant_id LEFT JOIN erp_job_vacancy v ON v.id=s.vacancy_id LEFT JOIN erp_interview_schedule i ON i.id=s.final_interview_id LEFT JOIN erp_position pos ON pos.id=s.proposed_position_id LEFT JOIN erp_job_title jt ON jt.id=s.proposed_job_title_id LEFT JOIN erp_employee_master app ON app.id=s.approved_by_employee_id WHERE s.id=? LIMIT 1",array((int)$id));}
function sr_payload($r){$d=(array)$r;$d['applicant_text']=$r->applicant_id?($r->applicant_no.' - '.$r->applicant_name):'';$d['vacancy_text']=$r->vacancy_id?($r->vacancy_no.' - '.$r->vacancy_title):'';$d['interview_text']=$r->final_interview_id?($r->interview_no):'';$d['position_text']=$r->proposed_position_id?($r->position_code.' - '.$r->position_name):'';$d['job_title_text']=$r->proposed_job_title_id?($r->job_title_code.' - '.$r->job_title_name):'';$d['approved_by_text']=$r->approved_by_employee_id?($r->approved_no.' - '.$r->approved_name):'';return $d;}
function sr_sync_applicant($applicantId){global $db;if((int)$applicantId<=0)return;$s=$db->fetch("SELECT * FROM erp_selection_result WHERE applicant_id=? ORDER BY selection_date DESC,id DESC LIMIT 1",array((int)$applicantId));if(!$s)return;$status=null;if($s->decision_result==='SELECTED')$status='OFFER';elseif($s->decision_result==='REJECTED')$status='REJECTED';elseif(in_array($s->decision_result,array('HOLD','WAITING_LIST','REINTERVIEW'),true))$status='INTERVIEW';if($status){$data=array('applicant_status'=>$status,'updated_by'=>'admin','updated_at'=>date('Y-m-d H:i:s'));if((float)$s->overall_score>0)$data['final_score']=$s->overall_score;if($s->decision_result==='REJECTED')$data['rejection_reason']=$s->rejected_reason;$db->update('erp_applicant_data',$data,'id',(int)$applicantId);}}
function sr_export_rows($from,$to,$status,$decision,$stage,$vacancyId,$kw){global $db;$p=array($from,$to);$w=" WHERE s.selection_date BETWEEN ? AND ? ";if($status!==''){$w.=" AND s.selection_status=? ";$p[]=$status;}if($decision!==''){$w.=" AND s.decision_result=? ";$p[]=$decision;}if($stage!==''){$w.=" AND s.selection_stage=? ";$p[]=$stage;}if($vacancyId!==''){$w.=" AND s.vacancy_id=? ";$p[]=(int)$vacancyId;}if($kw!==''){$like='%'.$kw.'%';$w.=" AND (s.selection_no LIKE ? OR a.applicant_no LIKE ? OR a.applicant_name LIKE ? OR v.vacancy_no LIKE ? OR v.vacancy_title LIKE ?) ";array_push($p,$like,$like,$like,$like,$like);}return $db->query("SELECT s.*,a.applicant_no,a.applicant_name,v.vacancy_no,v.vacancy_title,app.employee_no approved_no,app.full_name approved_name FROM erp_selection_result s LEFT JOIN erp_applicant_data a ON a.id=s.applicant_id LEFT JOIN erp_job_vacancy v ON v.id=s.vacancy_id LEFT JOIN erp_employee_master app ON app.id=s.approved_by_employee_id $w ORDER BY s.selection_date DESC,s.selection_no DESC",$p);}
$act=isset($_GET['act'])?$_GET['act']:'';$username=sr_user();$statuses=array('DRAFT','SUBMITTED','APPROVED','REJECTED','CANCELLED');$decisions=array('PENDING','SELECTED','REJECTED','HOLD','WAITING_LIST','REINTERVIEW');$stages=array('SCREENING','INTERVIEW','FINAL','OFFER_DECISION','HIRING_DECISION');$recs=array('PENDING','STRONG_HIRE','HIRE','HOLD','NO_HIRE','REINTERVIEW');$nexts=array('NONE','CREATE_OFFER','SCHEDULE_REINTERVIEW','KEEP_TALENT_POOL','CLOSE_APPLICATION');
