case 'vacancy_search':$t=trim(sr_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT id,vacancy_no,vacancy_title,vacancy_status FROM erp_job_vacancy WHERE (?='' OR vacancy_no LIKE ? OR vacancy_title LIKE ?) ORDER BY vacancy_no DESC LIMIT 50",array($t,$like,$like));sr_select2($rows,'id',function($r){return $r->vacancy_no.' - '.$r->vacancy_title.' ['.$r->vacancy_status.']';});
case 'employee_search':$t=trim(sr_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT id,employee_no,full_name,employment_status FROM erp_employee_master WHERE employment_status IN ('ACTIVE','PROBATION','CONTRACT') AND (?='' OR employee_no LIKE ? OR full_name LIKE ?) ORDER BY employee_no LIMIT 40",array($t,$like,$like));sr_select2($rows,'id',function($r){return $r->employee_no.' - '.$r->full_name.' ['.$r->employment_status.']';});
case 'position_search':$t=trim(sr_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT id,position_code,position_name FROM erp_position WHERE position_status IN ('APPROVED','ACTIVE','PLANNED') AND (?='' OR position_code LIKE ? OR position_name LIKE ?) ORDER BY position_code LIMIT 40",array($t,$like,$like));sr_select2($rows,'id',function($r){return $r->position_code.' - '.$r->position_name;});
case 'job_title_search':$t=trim(sr_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT id,job_title_code,job_title_name FROM erp_job_title WHERE status='ACTIVE' AND (?='' OR job_title_code LIKE ? OR job_title_name LIKE ?) ORDER BY job_title_code LIMIT 40",array($t,$like,$like));sr_select2($rows,'id',function($r){return $r->job_title_code.' - '.$r->job_title_name;});
case 'interview_search':$t=trim(sr_p('term'));$app=(int)sr_p('applicant_id');$like='%'.$t.'%';$rows=$db->query("SELECT id,interview_no,interview_type,interview_status,overall_score FROM erp_interview_schedule WHERE (?=0 OR applicant_id=?) AND (?='' OR interview_no LIKE ?) ORDER BY schedule_date DESC,id DESC LIMIT 40",array($app,$app,$t,$like));sr_select2($rows,'id',function($r){return $r->interview_no.' - '.$r->interview_type.' ['.$r->interview_status.' / '.$r->overall_score.']';});
case 'applicant_info':$r=$db->fetch("SELECT a.*,v.vacancy_no,v.vacancy_title,v.position_id,v.job_title_id,v.pay_grade,v.salary_min,v.salary_max,v.currency,v.target_join_date,pos.position_code,pos.position_name,jt.job_title_code,jt.job_title_name,i.id interview_id,i.interview_no FROM erp_applicant_data a LEFT JOIN erp_job_vacancy v ON v.id=a.vacancy_id LEFT JOIN erp_position pos ON pos.id=v.position_id LEFT JOIN erp_job_title jt ON jt.id=v.job_title_id LEFT JOIN erp_interview_schedule i ON i.applicant_id=a.id WHERE a.id=? ORDER BY i.schedule_date DESC,i.id DESC LIMIT 1",array((int)sr_p('id')));if(!$r)sr_json('error','Applicant tidak ditemukan.');sr_json('good','',array('data'=>array('vacancy_id'=>$r->vacancy_id,'vacancy_text'=>$r->vacancy_no.' - '.$r->vacancy_title,'final_interview_id'=>$r->interview_id,'interview_text'=>$r->interview_no,'screening_score'=>$r->screening_score,'interview_score'=>$r->interview_score,'overall_score'=>$r->final_score,'proposed_position_id'=>$r->position_id,'position_text'=>$r->position_code.' - '.$r->position_name,'proposed_job_title_id'=>$r->job_title_id,'job_title_text'=>$r->job_title_code.' - '.$r->job_title_name,'proposed_grade'=>$r->pay_grade,'proposed_salary'=>$r->salary_min,'currency'=>$r->currency,'proposed_join_date'=>$r->target_join_date)));
case 'get':$r=sr_row((int)sr_p('id'));if(!$r)sr_json('error','Selection Result tidak ditemukan.');sr_json('good','',array('data'=>sr_payload($r)));
case 'save':
  $id=(int)sr_p('id');$no=sr_c(sr_p('selection_no'));$date=trim(sr_p('selection_date'));if($no===''||$no==='AUTO')$no=sr_next_no($date!==''?(int)substr($date,0,4):date('Y'));$app=(int)sr_p('applicant_id');$stage=sr_c(sr_p('selection_stage','FINAL'));$status=sr_c(sr_p('selection_status','DRAFT'));$decision=sr_c(sr_p('decision_result','PENDING'));$rec=sr_c(sr_p('recommendation','PENDING'));$next=sr_c(sr_p('next_action','NONE'));
  if(!$app)sr_json('error','Applicant wajib dipilih.');if($date==='')sr_json('error','Selection Date wajib diisi.');if(!in_array($stage,$stages,true))sr_json('error','Stage tidak valid.');if(!in_array($status,$statuses,true))sr_json('error','Status tidak valid.');if(!in_array($decision,$decisions,true))sr_json('error','Decision tidak valid.');if(!in_array($rec,$recs,true))$rec='PENDING';if(!in_array($next,$nexts,true))$next='NONE';if($db->fetch("SELECT id FROM erp_selection_result WHERE selection_no=? AND id<>? LIMIT 1",array($no,$id)))sr_json('error','Selection No sudah digunakan.');
  $data=array('selection_no'=>$no,'applicant_id'=>$app,'vacancy_id'=>sr_p('vacancy_id')!==''?(int)sr_p('vacancy_id'):null,'final_interview_id'=>sr_p('final_interview_id')!==''?(int)sr_p('final_interview_id'):null,'selection_date'=>$date,'selection_stage'=>$stage,'selection_status'=>$status,'decision_result'=>$decision,'ranking_no'=>sr_p('ranking_no')!==''?(int)sr_p('ranking_no'):null,'screening_score'=>(float)sr_p('screening_score',0),'interview_score'=>(float)sr_p('interview_score',0),'assessment_score'=>(float)sr_p('assessment_score',0),'overall_score'=>(float)sr_p('overall_score',0),'recommendation'=>$rec,'proposed_position_id'=>sr_p('proposed_position_id')!==''?(int)sr_p('proposed_position_id'):null,'proposed_job_title_id'=>sr_p('proposed_job_title_id')!==''?(int)sr_p('proposed_job_title_id'):null,'proposed_grade'=>trim(sr_p('proposed_grade')),'proposed_salary'=>(float)sr_p('proposed_salary',0),'currency'=>sr_c(sr_p('currency','IDR'))?:'IDR','proposed_join_date'=>trim(sr_p('proposed_join_date'))?:null,'approved_by_employee_id'=>sr_p('approved_by_employee_id')!==''?(int)sr_p('approved_by_employee_id'):null,'approved_at'=>$status==='APPROVED'?(trim(sr_p('approved_at'))?:date('Y-m-d H:i:s')):null,'rejected_reason'=>trim(sr_p('rejected_reason')),'hold_reason'=>trim(sr_p('hold_reason')),'selection_committee_notes'=>trim(sr_p('selection_committee_notes')),'hr_notes'=>trim(sr_p('hr_notes')),'user_notes'=>trim(sr_p('user_notes')),'next_action'=>$next,'sap_reference'=>trim(sr_p('sap_reference')),'remarks'=>trim(sr_p('remarks')),'updated_by'=>$username,'updated_at'=>date('Y-m-d H:i:s'));
  if($data['overall_score']<=0){$parts=array_filter(array($data['screening_score'],$data['interview_score'],$data['assessment_score']),function($v){return $v>0;});$data['overall_score']=count($parts)?round(array_sum($parts)/count($parts),2):0;}
  if($id>0){if(!sr_row($id))sr_json('error','Selection Result tidak ditemukan.');$ok=$db->update('erp_selection_result',$data,'id',$id);}else{$data['created_by']=$username;$ok=$db->insert('erp_selection_result',$data);$id=(int)$db->last_insert_id();}
  if(!$ok)sr_json('error',$db->getErrorMessage()?:'Selection Result gagal disimpan.');sr_sync_applicant($app);if(function_exists('simpan_log'))simpan_log('User '.$username.' menyimpan Selection Result '.$no.' pada '.date('Y-m-d H:i:s'),$username);sr_json('good','Selection Result berhasil disimpan.',array('id'=>$id,'selection_no'=>$no));
